const express = require("express");
const { exec } = require("child_process");
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;
    exec(`whois ${domain}`, (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

response_text:
**1. Vulnerability Class:** Command Injection (CWE-78)

**2. Location:** `server.js`, line 7

**3. Explanation:** The application takes user-provided input from the `domain` query parameter and passes it directly into the `exec` function via a template literal. Because `exec` spawns a shell to execute the command, an attacker can use shell metacharacters (such as `;`, `&&`, `||`, or `` ` ``) to terminate the intended `whois` command and execute arbitrary system commands with the privileges of the Node.js process. For example, a request to `/whois?domain=google.com; cat /etc/passwd` would result in the server leaking the contents of the system password file.

**4. Proposed Fix:** Use `execFile` instead of `exec`. Unlike `exec`, `execFile` does not spawn a shell by default; it accepts the command and its arguments as separate elements in an array, ensuring that the arguments are passed directly to the binary without being interpreted as shell commands.

```javascript
const express = require("express");
const { execFile } = require("child_process"); // Change exec to execFile
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;

    // Basic validation to ensure domain is provided
    if (!domain || typeof domain !== 'string') {
        return res.status(400).send("Invalid domain provided");
    }

    // execFile takes the command and arguments separately, preventing shell injection
    execFile("whois", [domain], (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

